     4→export async function fetchGuideById(guideId: string): Promise<GuideDetail | null> {
     5→  const supabase = createClient();
     6→
     7→  const { data, error } = await supabase
     8→    .from("posts")
     9→    .select(`
    10→      *,
    11→      profile:profiles!posts_user_id_fkey(*),
    12→      category:categories!posts_category_id_fkey(*),
    13→      media:post_media(*),
    14→      chat_messages(*, annotation:message_annotations(*), star:message_stars(*)),
    15→      timeline_chapters(*)
    16→    `)
    17→    .eq("id", guideId)
    18→    .eq("is_hidden", false)
    19→    .single();
    20→
    21→  if (error || !data) return null;
    22→
    23→  // Sort media and chat_messages by order
    24→  if (data.media) {
    25→    (data.media as any[]).sort((a: any, b: any) => a.order - b.order);
    26→  }
    27→  if (data.chat_messages) {
    28→    (data.chat_messages as any[]).sort((a: any, b: any) => a.order - b.order);
    29→    // Map joined annotation (array→single) and star (presence→boolean)
    30→    for (const msg of data.chat_messages as any[]) {
    31→      const annArr = msg.annotation;
    32→      msg.annotation = Array.isArray(annArr) && annArr.length > 0 ? annArr[0] : undefined;
    33→      const starArr = msg.star;
    34→      msg.is_starred = Array.isArray(starArr) ? starArr.length > 0 : !!starArr;
    35→      delete msg.star;
    36→    }
    37→  }
    38→  if (data.timeline_chapters) {
    39→    (data.timeline_chapters as any[]).sort((a: any, b: any) => a.start_order - b.start_order);
    40→  }
    41→
    42→  return data as unknown as GuideDetail;
    43→}
