     5→-- Add follower/following counts to profiles
     6→alter table public.profiles
     7→  add column followers_count integer default 0 not null,
     8→  add column following_count integer default 0 not null;
     9→
    10→-- FOLLOWS
    11→create table public.follows (
    12→  follower_id uuid references public.profiles(id) on delete cascade not null,
    13→  following_id uuid references public.profiles(id) on delete cascade not null,
    14→  created_at timestamptz default now() not null,
    15→  primary key (follower_id, following_id),
    16→  constraint no_self_follow check (follower_id != following_id)
    17→);
    18→
    19→alter table public.follows enable row level security;
    20→
    21→create policy "Follows are viewable by everyone"
    22→  on public.follows for select using (true);
    23→
    24→create policy "Authenticated users can follow"
    25→  on public.follows for insert with check (auth.uid() = follower_id);
    26→
    27→create policy "Users can unfollow"
    28→  on public.follows for delete using (auth.uid() = follower_id);
    29→
    30→-- Indexes
    31→create index idx_follows_follower_id on public.follows(follower_id);
    32→create index idx_follows_following_id on public.follows(following_id);
