    34→-- Trigger to auto-update follow counts
    35→create or replace function public.update_follow_counts()
    36→returns trigger as $$
    37→begin
    38→  if (tg_op = 'INSERT') then
    39→    update public.profiles set following_count = following_count + 1 where id = new.follower_id;
    40→    update public.profiles set followers_count = followers_count + 1 where id = new.following_id;
    41→    return new;
    42→  elsif (tg_op = 'DELETE') then
    43→    update public.profiles set following_count = following_count - 1 where id = old.follower_id;
    44→    update public.profiles set followers_count = followers_count - 1 where id = old.following_id;
    45→    return old;
    46→  end if;
    47→  return null;
    48→end;
    49→$$ language plpgsql security definer;
